import json
from openai import OpenAI

client = OpenAI()

def classify_intent(ticket: str) -> dict:
    """Zero-shot intent classification with JSON mode enforcement."""
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        response_format={"type": "json_object"},
        messages=[
            {
                "role": "system",
                "content": (
                    "You are an intent classifier. "
                    "Return a JSON object with keys: "
                    "label (one of: billing, shipping, technical, other) "
                    "and confidence (one of: high, medium, low)."
                ),
            },
            {
                "role": "user",
                "content": f"Classify this support ticket:\n```\n{ticket}\n```",
            },
        ],
        max_tokens=60,
        temperature=0,
    )
    return json.loads(response.choices[0].message.content)

tickets = [
    "My package hasn't arrived and it has been two weeks.",
    "The API keeps returning a 500 error when I POST to /v2/events.",
    "I want to cancel my plan and get a refund.",
    "What are your business hours?",
]

for t in tickets:
    print(classify_intent(t))

import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();

const SYSTEM = `You are a precise JSON extraction engine.
Given an order confirmation email, extract the following fields:
  - orderId (string or null)
  - totalAmount (number in USD or null)
  - estimatedDelivery (ISO 8601 date string or null)
  - items (array of { name: string, quantity: number, unitPrice: number })

Return ONLY valid JSON matching this schema. If a field is not present, use null.`;

async function extractOrderEntities(emailText) {
  const response = await client.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 512,
    system: SYSTEM,
    messages: [
      {
        role: 'user',
        content: \`Extract order details from this email:\n\n\${emailText}\`,
      },
    ],
  });

  return JSON.parse(response.content[0].text);
}

