def safe_classify(ticket: str, max_retries: int = 2) -> dict | None:
    for attempt in range(max_retries + 1):
        raw = call_model(ticket)
        try:
            result = json.loads(raw)
            assert result.get("label") in {"billing", "shipping", "technical", "other"}
            return result
        except (json.JSONDecodeError, AssertionError):
            if attempt == max_retries:
                return None   # log and handle upstream
            # Retry with a corrective hint
            ticket = ticket + f"\n[Previous response was invalid JSON. Reply with only the JSON object.]"
